"use strict";(self.webpackChunkTartaria=self.webpackChunkTartaria||[]).push([[717],{3201:(l,i,e)=>{e.r(i),e.d(i,{data:()=>a});const a={key:"v-29aeb15c",path:"/aphorisms/",title:"Афоризмы",lang:"ru-RU",frontmatter:{sidebarDepth:2},excerpt:"",headers:[{level:2,title:"Самуил Яковлевич Маршак",slug:"самуил-яковлевич-маршак",children:[]},{level:2,title:"Станислав Ежи Лец",slug:"станислав-ежи-лец",children:[]},{level:2,title:"Татьяна и я",slug:"татьяна-и-я",children:[]},{level:2,title:"Уинстон Черчель",slug:"уинстон-черчель",children:[]},{level:2,title:"Шота Руставели",slug:"шота-руставели",children:[]},{level:2,title:"Разное",slug:"разное",children:[]},{level:2,title:"Из фильмов",slug:"из-фильмов",children:[{level:3,title:"Викинги",slug:"викинги",children:[]},{level:3,title:"Дедвуд",slug:"дедвуд",children:[]}]}],filePathRelative:"aphorisms/README.md",git:{updatedTime:1737305175e3,contributors:[{name:"blackchestnut",email:"alexander.kalinichev@gmail.com",commits:10},{name:"Alexander",email:"alexander.kalinichev@gmail.com",commits:2},{name:"Alex",email:"alexander.kalinichev@gmail.com",commits:1}]}}},2736:(l,i,e)=>{e.r(i),e.d(i,{default:()=>h});const a=(0,e(6252).uE)('<h1 id="афоризмы" tabindex="-1"><a class="header-anchor" href="#афоризмы" aria-hidden="true">#</a> Афоризмы</h1><h2 id="самуил-яковлевич-маршак" tabindex="-1"><a class="header-anchor" href="#самуил-яковлевич-маршак" aria-hidden="true">#</a> Самуил Яковлевич Маршак</h2><blockquote><p>(перевод Джона Харингтона)</p></blockquote><ul><li>Мятеж не может кончиться удачей, - в противном случае его звут иначе</li></ul><h2 id="станислав-ежи-лец" tabindex="-1"><a class="header-anchor" href="#станислав-ежи-лец" aria-hidden="true">#</a> Станислав Ежи Лец</h2><ul><li>Ах, если бы наша смерть уже не застала нас среди живых!</li><li>Бог не ангел</li><li>Бывает, что есть, куда воткнуть, но нет контакта</li><li>Бывает, что не хочется жить, но это еще не значит, что хочется не жить</li><li>В действительности все не так, как на самом деле</li><li>Возможно, и на пороге смерти прибита подкова счастья</li><li>Все люди братья, но не все братья люди</li><li>Жаль, что в рай надо ехать на катафалке!</li><li>Когда ошибки будут реже, они станут гораздо ценней</li><li>Лужа подчас производит глубокое впечатление</li><li>Любовь к родине не знает чужих границ</li><li>Можно закрыть глаза на действительность, но не на воспоминания</li><li>Не жди с мытьем ног до потопа!</li><li>Не каждая серая масса имеет что-то общее с мозгом</li><li>Не ходи проторенными дорожками — поскользнешься</li><li>Некрасиво подозревать, когда вполне уверен</li><li>О государстве лучше всего судить по тому, как в нём судят</li><li>Общество никогда не может простить тех, кто ни в чем не повинен</li><li>Оптимизм и пессимизм расходятся только в дате конца света</li><li>Пока ветра нет, и у флюгера есть свой характер</li><li>Порой надо умолкнуть, чтобы тебя выслушали</li><li>Привыкнуть можно только к смерти других</li><li>Ребенок рождает родителей</li><li>Совесть у него чистая. Не бывшая в употреблении</li><li>Создавайте легенды о себе. Боги начинали с этого</li><li>Сходят с ума только те, у кого он есть</li><li>Техника техникой, но лифт ломается чаще, чем лестница</li><li>Чем чище жертва, тем грязнее руки убийц</li><li>Чтобы добраться до источника, надо плыть против течения</li></ul><h2 id="татьяна-и-я" tabindex="-1"><a class="header-anchor" href="#татьяна-и-я" aria-hidden="true">#</a> Татьяна и я</h2><ul><li>Если было б всё так просто - был б ты маленького роста</li><li>Остановишь свои дела - и жизнь свою остановишь</li><li>Родишься - не поймешь, умрешь - не узнаешь</li><li>Старость - не радость, мудрость - не подарок</li><li>Творог не мясо - готовить не надо</li><li>Хорошо ли вам было сегодня, вы, узнаете только завтра</li></ul><hr><ul><li>Не ищи подводных камней на асфальте</li></ul><h2 id="уинстон-черчель" tabindex="-1"><a class="header-anchor" href="#уинстон-черчель" aria-hidden="true">#</a> Уинстон Черчель</h2><ul><li>Если тебя ненавидят, значит ты в своей жизни, что-то отстаивал</li></ul><h2 id="шота-руставели" tabindex="-1"><a class="header-anchor" href="#шота-руставели" aria-hidden="true">#</a> Шота Руставели</h2><ul><li>Кто себе друзей не ищет, самому себе он враг</li><li>Всех богатств добытых лучше добыванье доброй славы</li><li>Лучше смерть, но смерть со славой, чем постыдный в жизни путь</li><li>Другу верный друг поможет, не страшит его беда</li><li>Сердце он отдаст за сердце, а любовь - в пути звезда</li></ul><h2 id="разное" tabindex="-1"><a class="header-anchor" href="#разное" aria-hidden="true">#</a> Разное</h2><ul><li>Всё, сотворённое ранее, распадётся, не повторяясь</li><li>Освободите себя от надежды, что море когда-нибудь успокоится</li></ul><h2 id="из-фильмов" tabindex="-1"><a class="header-anchor" href="#из-фильмов" aria-hidden="true">#</a> Из фильмов</h2><h3 id="викинги" tabindex="-1"><a class="header-anchor" href="#викинги" aria-hidden="true">#</a> Викинги</h3><blockquote><p>(англ. Vikings)</p></blockquote><ul><li>То что мы заслужеваем и то, что получаем не всегда совпадает. Похоже богов не соишком беспокоит справедливость</li></ul><h3 id="дедвуд" tabindex="-1"><a class="header-anchor" href="#дедвуд" aria-hidden="true">#</a> Дедвуд</h3><blockquote><p>(англ. Deadwood)</p></blockquote><ul><li>От тех кто хочет оправдаться несчастья столько же, сколько и от тех, кто замыслил зло</li></ul>',23),r={},h=(0,e(3744).Z)(r,[["render",function(l,i){return a}]])},3744:(l,i)=>{i.Z=(l,i)=>{for(const[e,a]of i)l[e]=a;return l}}}]);